import{V as e}from"./chunks/theme.CwF41GzT.js";import{o,c as h,ak as r,J as t,k as a,j as i,a as u}from"./chunks/framework.CDHwDzB5.js";const d=JSON.parse('{"title":"鸣谢","description":"","frontmatter":{},"headers":[],"relativePath":"TTHSDNext/TTHSD_Docs/zh/acknowledgments/acknowledgments.md","filePath":"TTHSDNext/TTHSD_Docs/zh/acknowledgments/acknowledgments.md","lastUpdated":0}'),g={name:"TTHSDNext/TTHSD_Docs/zh/acknowledgments/acknowledgments.md"},k=Object.assign(g,{setup(p){const n=[{avatar:"https://images-sxxyrry.pages.dev/sxxyrryAvatar.jpg",name:"Sxxyrry",title:"项目负责人，作者",links:[{icon:"github",link:"https://github.com/sxxyrry"}]},{avatar:"https://images-sxxyrry.pages.dev/Wangziqi0Avatar.png",name:"Wangziqi0",title:"文档审查， Rust 版本主要修复者",links:[{icon:"github",link:"https://github.com/Wangziqi0"}]}],s=[{avatar:"https://images-sxxyrry.pages.dev/XiaoHuiHuiAvatar.jpg",name:"XiaoHuiHuiB",title:"文档审查和测试",links:[{icon:"github",link:"https://github.com/xiaohuihuib"}]},{avatar:"https://images-sxxyrry.pages.dev/ChengHaoLee-2012Avatar.jpg",name:"ChengHaoLee",title:"测试",links:[{icon:"github",link:"https://github.com/chenghaolee-2012"}]},{avatar:"https://images-sxxyrry.pages.dev/CGrakeskiAvatar.jpg",name:"CGrakeski",title:"文档审查",links:[{icon:"github",link:"https://github.com/CGrakeski"}]},{avatar:"https://images-sxxyrry.pages.dev/w1wenjieAvatar.png",name:"w1wenjie",title:"文档审查",links:[{icon:"github",link:"https://github.com/w1wenjie"}]}];return(b,l)=>(o(),h("div",null,[l[0]||(l[0]=r('<h1 id="鸣谢" tabindex="-1">鸣谢 <a class="header-anchor" href="#鸣谢" aria-label="Permalink to “鸣谢”">​</a></h1><p>TT 高速下载器 (TTHSD) 项目的成功离不开开源社区的支持和众多贡献者的努力。在此，我们向所有帮助过项目的人和组织表示最诚挚的感谢。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>本文档介绍的是 <strong>TTHSD Next</strong>（Rust 版本）的鸣谢信息。</p><p><a href="https://github.com/sxxyrry/TTHighSpeedDownloader" target="_blank" rel="noreferrer">TTHSD Golang</a> 已停止开发，但我们仍然感谢所有为 Golang 版本做出贡献的人。</p></div><h2 id="核心依赖项目" tabindex="-1">核心依赖项目 <a class="header-anchor" href="#核心依赖项目" aria-label="Permalink to “核心依赖项目”">​</a></h2><p>TTHSD Next 的开发离不开以下优秀的开源项目：</p><h3 id="rust-语言生态" tabindex="-1">Rust 语言生态 <a class="header-anchor" href="#rust-语言生态" aria-label="Permalink to “Rust 语言生态”">​</a></h3><h4 id="异步运行时与并发" tabindex="-1">异步运行时与并发 <a class="header-anchor" href="#异步运行时与并发" aria-label="Permalink to “异步运行时与并发”">​</a></h4><ul><li><p><strong><a href="https://github.com/tokio-rs/tokio" target="_blank" rel="noreferrer">tokio</a></strong> - 异步运行时</p><ul><li>提供了高效的异步 I/O 和任务调度</li><li>版本: 1.40</li><li>许可证: MIT</li></ul></li><li><p><strong><a href="https://github.com/tokio-rs/tokio" target="_blank" rel="noreferrer">tokio-util</a></strong> - Tokio 实用工具</p><ul><li>提供了额外的异步实用功能</li><li>版本: 0.7</li><li>许可证: MIT</li></ul></li><li><p><strong><a href="https://github.com/rust-lang/futures-rs" target="_blank" rel="noreferrer">futures</a></strong> - Future 抽象</p><ul><li>提供了异步编程的核心抽象</li><li>版本: 0.3.32</li><li>许可证: MIT OR Apache-2.0</li></ul></li><li><p><strong><a href="https://github.com/dtolnay/async-trait" target="_blank" rel="noreferrer">async-trait</a></strong> - 异步 trait 支持</p><ul><li>提供了在 trait 中使用 async 的能力</li><li>版本: 0.1</li><li>许可证: MIT OR Apache-2.0</li></ul></li></ul><h4 id="http-客户端" tabindex="-1">HTTP 客户端 <a class="header-anchor" href="#http-客户端" aria-label="Permalink to “HTTP 客户端”">​</a></h4><ul><li><p><strong><a href="https://github.com/penumbra-x/rquest" target="_blank" rel="noreferrer">rquest</a></strong> - HTTP 客户端</p><ul><li>提供了支持 TLS 指纹模拟的异步 HTTP 客户端</li><li>版本: 5.1</li><li>许可证: Apache-2.0</li></ul></li><li><p><strong><a href="https://github.com/penumbra-x/rquest" target="_blank" rel="noreferrer">rquest-util</a></strong> - rquest 工具库</p><ul><li>提供了浏览器指纹模拟功能</li><li>版本: 2.2</li><li>许可证: Apache-2.0</li></ul></li></ul><h4 id="http-3-quic" tabindex="-1">HTTP/3 (QUIC) <a class="header-anchor" href="#http-3-quic" aria-label="Permalink to “HTTP/3 (QUIC)”">​</a></h4><ul><li><p><strong><a href="https://github.com/quinn-rs/quinn" target="_blank" rel="noreferrer">quinn</a></strong> - QUIC 协议实现</p><ul><li>提供了纯 Rust 的 QUIC 协议栈</li><li>版本: 0.11</li><li>许可证: MIT OR Apache-2.0</li></ul></li><li><p><strong><a href="https://github.com/hyperium/h3" target="_blank" rel="noreferrer">h3</a></strong> - HTTP/3 实现</p><ul><li>提供了 HTTP/3 协议支持</li><li>版本: 0.0.8</li><li>许可证: MIT</li></ul></li><li><p><strong><a href="https://github.com/hyperium/h3" target="_blank" rel="noreferrer">h3-quinn</a></strong> - h3 与 quinn 集成</p><ul><li>提供了 h3 与 quinn 的集成层</li><li>版本: 0.0.10</li><li>许可证: MIT</li></ul></li></ul><h4 id="tls-加密" tabindex="-1">TLS 加密 <a class="header-anchor" href="#tls-加密" aria-label="Permalink to “TLS 加密”">​</a></h4><ul><li><p><strong><a href="https://github.com/rustls/rustls" target="_blank" rel="noreferrer">rustls</a></strong> - TLS 实现</p><ul><li>提供了纯 Rust 的 TLS 支持</li><li>版本: 0.23</li><li>许可证: Apache-2.0 OR MIT OR ISC</li></ul></li><li><p><strong><a href="https://github.com/rustls/webpki-roots" target="_blank" rel="noreferrer">webpki-roots</a></strong> - CA 证书</p><ul><li>提供了 Mozilla 的根证书集合</li><li>版本: 0.26</li><li>许可证: MPL-2.0</li></ul></li></ul><h4 id="文件传输协议" tabindex="-1">文件传输协议 <a class="header-anchor" href="#文件传输协议" aria-label="Permalink to “文件传输协议”">​</a></h4><ul><li><p><strong><a href="https://github.com/veeso/suppaftp" target="_blank" rel="noreferrer">suppaftp</a></strong> - FTP 客户端</p><ul><li>提供了异步 FTP 协议支持</li><li>版本: 8.0</li><li>许可证: MIT</li></ul></li><li><p><strong><a href="https://github.com/warp-tech/russh" target="_blank" rel="noreferrer">russh</a></strong> - SSH 客户端</p><ul><li>提供了纯 Rust 的 SSH 协议支持</li><li>版本: 0.46</li><li>许可证: Apache-2.0</li></ul></li><li><p><strong><a href="https://github.com/warp-tech/russh" target="_blank" rel="noreferrer">russh-sftp</a></strong> - SFTP 客户端</p><ul><li>提供了基于 russh 的 SFTP 支持</li><li>版本: 2.0</li><li>许可证: Apache-2.0</li></ul></li></ul><h4 id="bittorrent" tabindex="-1">BitTorrent <a class="header-anchor" href="#bittorrent" aria-label="Permalink to “BitTorrent”">​</a></h4><ul><li><strong><a href="https://github.com/ikatson/rqbit" target="_blank" rel="noreferrer">librqbit</a></strong> - BitTorrent 客户端 <ul><li>提供了纯 Rust 的 BitTorrent 协议支持</li><li>版本: 8.1</li><li>许可证: MIT</li></ul></li></ul><h4 id="metalink" tabindex="-1">Metalink <a class="header-anchor" href="#metalink" aria-label="Permalink to “Metalink”">​</a></h4><ul><li><strong><a href="https://github.com/mpolden/metalink-rs" target="_blank" rel="noreferrer">metalink</a></strong> - Metalink 解析 <ul><li>提供了 Metalink 4.0 XML 解析支持</li><li>版本: 0.1</li><li>许可证: MIT</li></ul></li></ul><h4 id="序列化与数据" tabindex="-1">序列化与数据 <a class="header-anchor" href="#序列化与数据" aria-label="Permalink to “序列化与数据”">​</a></h4><ul><li><p><strong><a href="https://github.com/serde-rs/serde" target="_blank" rel="noreferrer">serde</a></strong> - 序列化框架</p><ul><li>提供了高效的序列化和反序列化功能</li><li>版本: 1.0</li><li>许可证: MIT OR Apache-2.0</li></ul></li><li><p><strong><a href="https://github.com/serde-rs/json" target="_blank" rel="noreferrer">serde_json</a></strong> - JSON 支持</p><ul><li>提供了 JSON 序列化支持</li><li>版本: 1.0</li><li>许可证: MIT OR Apache-2.0</li></ul></li><li><p><strong><a href="https://github.com/tokio-rs/bytes" target="_blank" rel="noreferrer">bytes</a></strong> - 字节处理</p><ul><li>提供了高效的字节缓冲区管理</li><li>版本: 1</li><li>许可证: MIT</li></ul></li></ul><h4 id="websocket" tabindex="-1">WebSocket <a class="header-anchor" href="#websocket" aria-label="Permalink to “WebSocket”">​</a></h4><ul><li><strong><a href="https://github.com/snapview/tokio-tungstenite" target="_blank" rel="noreferrer">tokio-tungstenite</a></strong> - WebSocket 客户端 <ul><li>提供了基于 tokio 的 WebSocket 支持</li><li>版本: 0.24</li><li>许可证: MIT</li></ul></li></ul><h4 id="工具库" tabindex="-1">工具库 <a class="header-anchor" href="#工具库" aria-label="Permalink to “工具库”">​</a></h4><ul><li><p><strong><a href="https://github.com/servo/rust-url" target="_blank" rel="noreferrer">url</a></strong> - URL 解析</p><ul><li>提供了 URL 解析和处理功能</li><li>版本: 2</li><li>许可证: MIT OR Apache-2.0</li></ul></li><li><p><strong><a href="https://github.com/matklad/once_cell" target="_blank" rel="noreferrer">once_cell</a></strong> - 延迟初始化</p><ul><li>提供了线程安全的延迟初始化</li><li>版本: 1.21.3</li><li>许可证: MIT OR Apache-2.0</li></ul></li><li><p><strong><a href="https://github.com/rust-lang-nursery/lazy-static.rs" target="_blank" rel="noreferrer">lazy_static</a></strong> - 静态延迟初始化</p><ul><li>提供了静态变量的延迟初始化</li><li>版本: 1.5.0</li><li>许可证: MIT OR Apache-2.0</li></ul></li><li><p><strong><a href="https://github.com/seanmonstar/num_cpus" target="_blank" rel="noreferrer">num_cpus</a></strong> - CPU 核心数</p><ul><li>提供了获取系统 CPU 核心数的功能</li><li>版本: 1.16</li><li>许可证: MIT OR Apache-2.0</li></ul></li><li><p><strong><a href="https://github.com/hyperium/http" target="_blank" rel="noreferrer">http</a></strong> - HTTP 类型</p><ul><li>提供了 HTTP 相关的类型定义</li><li>版本: 1</li><li>许可证: MIT OR Apache-2.0</li></ul></li></ul><h4 id="跨语言绑定" tabindex="-1">跨语言绑定 <a class="header-anchor" href="#跨语言绑定" aria-label="Permalink to “跨语言绑定”">​</a></h4><ul><li><strong><a href="https://github.com/jni-rs/jni-rs" target="_blank" rel="noreferrer">jni</a></strong> - Rust JNI 绑定 <ul><li>提供了 Rust 与 Java/Kotlin 的互操作性</li><li>版本: 0.21</li><li>许可证: MIT OR Apache-2.0</li></ul></li></ul><h3 id="构建工具" tabindex="-1">构建工具 <a class="header-anchor" href="#构建工具" aria-label="Permalink to “构建工具”">​</a></h3><ul><li><strong><a href="https://www.rust-lang.org/" target="_blank" rel="noreferrer">Rust</a></strong> - Rust 编程语言 <ul><li>提供了强大的内存安全保证和零成本抽象</li><li>使 TTHSD Next 能够轻松支持 Windows、Linux、macOS、Android 和 HarmonyOS 平台</li></ul></li></ul><h3 id="python-接口" tabindex="-1">Python 接口 <a class="header-anchor" href="#python-接口" aria-label="Permalink to “Python 接口”">​</a></h3><ul><li><strong><a href="https://docs.python.org/3/library/ctypes.html" target="_blank" rel="noreferrer">ctypes</a></strong> - Python 外部函数库 <ul><li>提供了 Python 与 C 动态库的互操作性</li><li>Python 标准库的一部分</li></ul></li></ul><h3 id="typescript-接口" tabindex="-1">TypeScript 接口 <a class="header-anchor" href="#typescript-接口" aria-label="Permalink to “TypeScript 接口”">​</a></h3><ul><li><strong><a href="https://github.com/node-ffi-napi/node-ffi-napi" target="_blank" rel="noreferrer">ffi-napi</a></strong> - Node.js FFI 库 <ul><li>提供了 Node.js 与 C 动态库的互操作性</li><li>许可证: MIT</li></ul></li><li><strong><a href="https://github.com/Koromix/koffi" target="_blank" rel="noreferrer">koffi</a></strong> - Node.js FFI 库 <ul><li>提供了更简洁的 Node.js 与 C 动态库的互操作性</li><li>许可证: MIT</li></ul></li></ul><h3 id="golang-依赖-由于其已停止开发所以这里只花一小点篇幅提到" tabindex="-1">Golang 依赖（由于其已停止开发所以这里只花一小点篇幅提到） <a class="header-anchor" href="#golang-依赖-由于其已停止开发所以这里只花一小点篇幅提到" aria-label="Permalink to “Golang 依赖（由于其已停止开发所以这里只花一小点篇幅提到）”">​</a></h3><ul><li><p><strong><a href="https://github.com/gorilla/websocket" target="_blank" rel="noreferrer">gorilla/websocket</a></strong> - WebSocket 库</p><ul><li><p>提供了稳定、高效的WebSocket通信支持</p></li><li><p>版本:v1.5.3</p></li><li><p>许可证：BSD-2-Clause</p></li></ul></li><li><p><strong><a href="https://golang.org/" target="_blank" rel="noreferrer">Go</a></strong> - Go编程语言</p><ul><li><p>提供了强大的并发特性和跨平台编译能力</p></li><li><p>使TTHSD能够轻松支持Windows、Linux 和macOS平台</p></li></ul></li></ul><h2 id="项目团队" tabindex="-1">项目团队 <a class="header-anchor" href="#项目团队" aria-label="Permalink to “项目团队”">​</a></h2><h3 id="核心开发" tabindex="-1">核心开发 <a class="header-anchor" href="#核心开发" aria-label="Permalink to “核心开发”">​</a></h3>',38)),t(a(e),{size:"small",members:n}),l[1]||(l[1]=i("h3",{id:"贡献者",tabindex:"-1"},[u("贡献者 "),i("a",{class:"header-anchor",href:"#贡献者","aria-label":"Permalink to “贡献者”"},"​")],-1)),t(a(e),{size:"small",members:s}),l[2]||(l[2]=r('<h2 id="社区贡献者" tabindex="-1">社区贡献者 <a class="header-anchor" href="#社区贡献者" aria-label="Permalink to “社区贡献者”">​</a></h2><p>感谢以下开发者对项目的贡献：</p><ul><li>感谢所有提交 Issue 和 Pull Request 的开发者</li><li>感谢提供宝贵建议和反馈的用户</li><li>感谢帮助完善文档的贡献者</li></ul><h2 id="特别感谢" tabindex="-1">特别感谢 <a class="header-anchor" href="#特别感谢" aria-label="Permalink to “特别感谢”">​</a></h2><ul><li>感谢所有使用 TTHSD Next 的用户和开发者，您的反馈和建议是我们持续改进的动力</li><li>感谢开源社区提供的宝贵资源和支持</li><li>感谢 Rust 社区提供的优秀工具和库</li><li>感谢所有为 <a href="https://github.com/sxxyrry/TTHighSpeedDownloader" target="_blank" rel="noreferrer">TTHSD Golang</a> 版本做出贡献的人，为项目奠定了基础</li></ul><h2 id="资源支持" tabindex="-1">资源支持 <a class="header-anchor" href="#资源支持" aria-label="Permalink to “资源支持”">​</a></h2><ul><li><strong><a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a></strong> - 文档站点构建工具</li><li><strong><a href="https://github.com/" target="_blank" rel="noreferrer">GitHub</a></strong> - 代码托管和协作平台</li></ul><h2 id="tthsd-next-vs-tthsd-golang" tabindex="-1">TTHSD Next vs TTHSD Golang <a class="header-anchor" href="#tthsd-next-vs-tthsd-golang" aria-label="Permalink to “TTHSD Next vs TTHSD Golang”">​</a></h2><p>感谢所有参与 TTHSD Golang 版本开发和测试的贡献者。虽然 TTHSD Golang 已停止开发，但您的贡献为 TTHSD Next 的开发奠定了坚实的基础。</p><p>TTHSD Next 在 TTHSD Golang 的基础上进行了重写，使用 Rust 语言实现了更高的性能、更低的内存占用和更稳定的运行表现。</p><hr><h2 id="如何贡献" tabindex="-1">如何贡献 <a class="header-anchor" href="#如何贡献" aria-label="Permalink to “如何贡献”">​</a></h2><p>如果您想为 TTHSD Next 做出贡献，我们欢迎以下形式的帮助：</p><ul><li><strong>代码贡献</strong>：提交 Pull Request 修复 bug 或添加新功能</li><li><strong>文档改进</strong>：完善文档，纠正错误，或翻译文档</li><li><strong>问题反馈</strong>：提交 Issue 报告 bug 或提出功能建议</li><li><strong>测试验证</strong>：在不同平台和场景下测试 TTHSD Next 的功能</li><li><strong>推广分享</strong>：向他人介绍和推荐 TTHSD Next</li></ul><p><a href="/TTHSD/zh/guide/contributing.html">查看贡献指南</a> | <a href="https://github.com/TTHSDownloader/TTHSDNext/issues" target="_blank" rel="noreferrer">提交 Issue</a> | <a href="https://github.com/TTHSDownloader/TTHSDNext/pulls" target="_blank" rel="noreferrer">发起 Pull Request</a></p><hr><p><strong>再次感谢所有为 TTHSD 项目提供帮助的人和组织！</strong> 🎉</p><p>无论是 TTHSD Golang 还是 TTHSD Next，每一份贡献都让项目变得更好！</p>',18))]))}});export{d as __pageData,k as default};
